text:
{
  "domains": [
    {
      "id": "property-data-management",
      "name": "Property Data Management",
      "ubiquitous_language": [
        {
          "term": "PropertyAsset",
          "definition": "A record representing physical property data including images and 3D assets (Splats), managed across ingestion and mobile capture contexts."
        },
        {
          "term": "MediaManifest",
          "definition": "A structured index entry describing uploaded assets, including format validation (PNG, JPG, GLTF) and storage location."
        },
        {
          "term": "OfflineBuffer",
          "definition": "A temporary storage container for mobile-captured data held locally until network reconnection enables synchronization."
        }
      ],
      "system_requirement_ids": [
        "SR-001",
        "SR-008"
      ]
    },
    {
      "id": "service-provider-matching",
      "name": "Service Provider Matching",
      "ubiquitous_language": [
        {
          "term": "HomeRealProperty",
          "definition": "A restricted category of service providers and categories limited to home real property services, excluding general contractors."
        },
        {
          "term": "ProviderProfile",
          "definition": "A searchable record containing provider service capabilities, location, and relevance score calculated by the AI Agent."
        },
        {
          "term": "BidEstimate",
          "definition": "A service quote entry used to render comparison views, requiring minimum three entries for display."
        },
        {
          "term": "MatchScore",
          "definition": "A calculated relevance metric indicating provider quality, used to rank top 5 results within 300ms."
        }
      ],
      "system_requirement_ids": [
        "SR-002",
        "SR-003"
      ]
    },
    {
      "id": "compliance-rules-engine",
      "name": "Compliance Rules Engine",
      "ubiquitous_language": [
        {
          "term": "BylawsClause",
          "definition": "An extracted text segment from CC&R or Bylaws documents with a confidence score greater than 90% highlighting relevant sections."
        },
        {
          "term": "StatutoryDeadline",
          "definition": "A calculated time limit for regulatory obligations, triggering alerts 30 days prior to the deadline date."
        },
        {
          "term": "NoticeRequirement",
          "definition": "A regulatory rule set defining mandatory communication content and timing based on local jurisdiction."
        },
        {
          "term": "ExtractionConfidence",
          "definition": "A metric indicating the AI's certainty level in CC&R/Bylaws clause extraction."
        }
      ],
      "system_requirement_ids": [
        "SR-004",
        "SR-006"
      ]
    },
    {
      "id": "action-workflow-orchestrator",
      "name": "Action Workflow Orchestrator",
      "ubiquitous_language": [
        {
          "term": "ActionItem",
          "definition": "A unit of work requiring a specific workflow state transition, recorded in the versioned audit log."
        },
        {
          "term": "WorkflowState",
          "definition": "A discrete status value representing progress of an ActionItem (e.g., Pending, In-Progress, Complete)."
        },
        {
          "term": "TransitionLog",
          "definition": "An immutable audit record tracking state changes with 100ms timestamp precision."
        }
      ],
      "system_requirement_ids": [
        "SR-005"
      ]
    },
    {
      "id": "notification-dispatcher",
      "name": "Notification Dispatcher",
      "ubiquitous_language": [
        {
          "term": "MessageBatch",
          "definition": "A collection of email/SMS payloads processed together, tracking delivery status for bulk communication channels."
        },
        {
          "term": "DeliveryAttempt",
          "definition": "A status record of a specific message transmission attempt, including bounce rate and retry logic."
        },
        {
          "term": "RecipientList",
          "definition": "A scoped collection of tenant members targeted for a specific regulatory or service message."
        }
      ],
      "system_requirement_ids": [
        "SR-007"
      ]
    },
    {
      "id": "tenant-security-gateway",
      "name": "Tenant Security Gateway",
      "ubiquitous_language": [
        {
          "term": "RLSPolicy",
          "definition": "A row-level security configuration enforcing data isolation between multi-tenant environments."
        },
        {
          "term": "TenantBoundary",
          "definition": "The logical data scope accessible by a specific tenant entity within the multi-tenant database."
        },
        {
          "term": "AccessLevel",
          "definition": "A permission tier defining what data an authenticated Homeowner can view or modify."
        }
      ],
      "system_requirement_ids": [
        "SR-009"
      ]
    },
    {
      "id": "payment-transaction-processor",
      "name": "Payment Transaction Processor",
      "ubiquitous_language": [
        {
          "term": "PaymentIntent",
          "definition": "A request to process deposits or service fees via Stripe/Square, returning authorization within 5 seconds."
        },
        {
          "term": "ReceiptDocument",
          "definition": "A generated electronic proof of payment sent to the Homeowner upon successful authorization."
        },
        {
          "term": "DepositFee",
          "definition": "A specific financial transaction line item associated with service engagement or system usage."
        }
      ],
      "system_requirement_ids": [
        "SR-010"
      ]
    }
  ]
}
